local LCityBuildingMgr = classX("LCityBuildingMgr", LCityBase)

function LCityBuildingMgr:ctor(cityView)
    LCityBase.ctor(self)

    ---@type LCityView
    self._cityView = cityView
end
function LCityBuildingMgr:Initialize()
    self._inViewCameraSize = GameTable.BuildingConfigRef.cameraInRate
    ---@type table<number, LCityBuilding> @id,obj
    self._buildings = {}

    ---@type table<number,LCityBuildingHud>
    self._buildingHUDs = {}

    ---@type table<string, LCityBuilding> @name,obj
    self._nameToBuildingMap = {}
    self.hudCanvasRoot = nil
    ---@type table<number>
    self._storyBuildingId = {}
    self._dropHudObj = nil
    LCityBase.Initialize(self)
    self:AddGpEvent(CityEvent.ShowBuildNameHudInfo, function(data)
        self:ShowBuildNameHUD()
    end,self)
    self:AddGpEvent(CityEvent.FadeHideBuildNameHudInfo, function(data)
        self:FadeHideBuildNameHUD()
    end,self)
    self:AddGpEvent(CityEvent.RefreshBuildUpgrade, function(data)
        self:RefreshBuildInfo()
        self:RefreshHelpIconInfo()
    end,self)

    self:AddGpEvent(CityEvent.RefreshBuildProductionTask, function(data)
