function LCityBuildingMgr:BuildingIsInStory(buildId)
    for i, v in pairs(self._storyBuildingId) do
        if(buildId == v)then
            return true
        end
    end
    return false
end
function LCityBuildingMgr:AddStoryBuilding(buildId)
    self._storyBuildingId = self._storyBuildingId or {}
    local exists = false
    for i, v in ipairs(self._storyBuildingId) do
        if(buildId == v)then
            exists = true
            break
        end
    end
    if(exists == false)then
        table.insert(self._storyBuildingId,buildId)
    end
end
function LCityBuildingMgr:DisposeStoryBuilding()
    table.dispose(self._storyBuildingId)
end
