function LCityBuildingMgr:Dispose()

    if self._isDisposed then return end
    table.dispose(self._storyBuildingId)
    table.dispose(self._nameToBuildingMap)
    self._nameToBuildingMap = nil
    for k,v in pairs(self._buildings) do
        v:Dispose()
    end
    table.dispose(self._buildings)
    self._buildings = nil
    for i, v in pairs(self._buildingHUDs) do
        v:DisposeReal();
        v:Dispose()
    end
    table.dispose(self._buildingHUDs)
    self._buildingHUDs = nil
    LCityBase.Dispose(self)
end

function LCityBuildingMgr:InitBuildings()
    local buildingTbl = GameTable.BuildingRef
    local rootTrans = self._rootNodeTrans
    self._hudObj = FindChild(self.hudCanvasRoot,"BuildingHud")
    self._dropHudObj = FindChild(self.hudCanvasRoot,"ProduceHud")
    for k,v in pairs(buildingTbl) do
        local nodeName = v.nodeName
        local obj = rootTrans:Find(nodeName)
        self:AddBuilding(k, nodeName, obj)

    end
end

function LCityBuildingMgr:SetRootNode(node,canvasNode)
    self._rootNode = node
    self._rootNodeTrans = node.transform
    self.hudCanvasRoot = canvasNode;
end

function LCityBuildingMgr:GetBuildingByName(nodeName)
    return self._nameToBuildingMap[nodeName]
end

function LCityBuildingMgr:GetBuilding(id)
    return self._buildings[id]
end
function LCityBuildingMgr:GetBuildingPos(id)
    if(self._buildings[id])then
        return self._buildings[id]._buildingTrans.position;
    end
end
function LCityBuildingMgr:AddBuildingHUD(id,buildingTrans,hudObj)
    local buildingHud = self._buildingHUDs[id]
    if(buildingHud)then
        return buildingHud
    end
    buildingHud = require("LApp.gameplay.city.view.LCityBuildingHud"):new(self._cityView)
    self._buildingHUDs[id] = buildingHud;
    local hud = InstantObject(self._hudObj)
    hud.name = "Building:"..id
    hud.transform:SetParent(MgrCenter.UIMgr._hudCanvasTrans)
    hud.transform.localScale = Vector3.one
    PJXUtil.SetLayerMask(hud.transform,"UI")
    buildingHud:InitBuilding(id,buildingTrans,hud,self)
    return buildingHud

end
function LCityBuildingMgr:AddBuilding(id, nodeName, buildingTrans)
    local building = self._buildings[id]
    if building then
        building:SetBuildingObj(buildingTrans)
        self._nameToBuildingMap[nodeName] = building
        return building
    end

    building = require("LApp.gameplay.city.view.LCityBuilding"):new(self._cityView)
    self._buildings[id] = building
    self._nameToBuildingMap[nodeName] = building
    building:SetLoadCallback(self.OnBuildingLoaded,self)
    building:InitBuilding(id, buildingTrans)

    return building
end

function LCityBuildingMgr:UsePeopleSkill(data)
    for i, v in pairs(self._buildingHUDs) do
        v:UsePeopleSkill(data.skillId)
    end

end
function LCityBuildingMgr:IsShowInView(size)
    if(size <= self._inViewCameraSize)then
        for i, v in pairs(self._buildings) do
            v:PlayInView()
        end
    else
        for i, v in pairs(self._buildings) do
            v:PlayOutView()
        end
    end
end

---建筑是否显示
function LCityBuildingMgr:GetBuildingShow(buildingId)

    local buildConfig = GameTable.BuildingRef[buildingId]
    local funcId = buildConfig.open
    return CtrlCenter.FuncOpen:IsFuncShow(funcId)

end
function LCityBuildingMgr:GetHUD(building)
    return self._buildingHUDs[building]
end

function LCityBuildingMgr:OnBuildingLoaded(buildingId)
    local building = self:GetBuilding(buildingId)

    local hud = self:GetHUD(buildingId)
    if(hud == nil)then
       hud = self:AddBuildingHUD(buildingId,building._buildingTrans,self._hudObj)
    else
        hud:InitBuilding(buildingId,building._buildingTrans,hud._hudObj,self)
    end

end
function LCityBuildingMgr:ShowLevelUpEffect(building)
    self:GetBuilding(building):ShowLevelUpEffect()
end
function LCityBuildingMgr:OnUpdate(deltaTime)
    if self._isDisposed then return end

    for k,v in pairs(self._buildings) do
        v:OnUpdate(deltaTime)
    end
    for i, v in pairs(self._buildingHUDs) do
        v:OnUpdate(deltaTime)
    end
end
function LCityBuildingMgr:GetEatNodeName(peopleRefId)
    local building = self:GetBuilding(2005)
    if(building == nil)then
        return
    end
    for i, v in pairs(building._eatingNodeNames) do
        if(v == 0)then
            local nodeName = i
            building:SetEatPeople(nodeName,peopleRefId)
            return nodeName
        end
    end
    return nil
end
function LCityBuildingMgr:ResetEatNode(nodeName)
    local building = self:GetBuilding(2005)
    if(building == nil)then
        return
    end
    building:ResetEatNode(nodeName)
end
return LCityBuildingMgr
